/**
 * /api/recommend
 *
 * Data-grounded recommendation endpoint.
 * Flow:
 *   1. Parse user message → extract structured input (normalizer)
 *   2. LLM extracts/refines fields from conversation history
 *   3. Run match engine against normalized product data
 *   4. Enrich with inventory + lead time
 *   5. Generate safe summary (deterministic, no hallucination)
 *   6. Optional: LLM polishes summary text only
 *
 * Hallucination prevention:
 *   - Product codes, specs, stock, lead time NEVER generated by LLM
 *   - All numeric values come from normalized JSON files
 *   - LLM only writes natural-language explanation of real results
 */

import { NextResponse } from "next/server"
import { normalizeInput, mergeInputs } from "@/lib/domain/input-normalizer"
import { runMatchEngine, classifyResults } from "@/lib/domain/match-engine"
import { buildDeterministicSummary, buildRationale, buildWarnings } from "@/lib/domain/summary-generator"
import { getProvider } from "@/lib/llm/provider"
import type { RecommendationInput, RecommendationResult } from "@/lib/types/canonical"

export const maxDuration = 60

const EXTRACTION_SYSTEM_PROMPT = `
You are a YG-1 cutting tool recommendation assistant.
Your job is to extract structured search parameters from the user's message.

ALWAYS respond with valid JSON only. No markdown, no explanation text.

Extract these fields if present:
{
  "material": string | null,          // material name in Korean or English
  "operationType": string | null,     // 황삭/정삭/중삭/고이송/슬롯/측면 etc.
  "diameterMm": number | null,        // diameter in mm
  "flutePreference": number | null,   // number of flutes (2,3,4,5,6...)
  "coatingPreference": string | null, // coating type if specified
  "isComplete": boolean,              // true if enough info to recommend
  "chips": string[],                  // 3-5 quick-reply suggestions in Korean
  "questionText": string              // next question to ask user (Korean, friendly)
}

Rules:
- Extract ONLY what the user explicitly states
- Do NOT invent or assume values not mentioned
- isComplete = true only when at least material AND (diameter OR operation) are known
- chips = most likely answers to your questionText
- questionText should be natural Korean

Examples of chip arrays:
- ["알루미늄", "스테인리스", "탄소강", "티타늄", "모름"]
- ["황삭", "정삭", "고이송", "슬롯가공", "측면가공"]
- ["2mm", "4mm", "6mm", "8mm", "10mm", "직접 입력"]
- ["2날", "4날", "6날", "상관없음"]
`

const SUMMARY_SYSTEM_PROMPT = `
You are a YG-1 cutting tool sales assistant writing a recommendation summary in Korean.

CRITICAL RULES — violations are not acceptable:
1. NEVER invent product codes, EDP numbers, or specifications
2. NEVER generate inventory quantities or lead times
3. NEVER say a product "exists" if it's not in the provided data
4. Use ONLY the product data and recommendation result provided to you
5. Keep the summary to 2-3 sentences max
6. Be honest about approximate matches ("근사 후보" = approximate candidate)
7. If data is missing, say "데이터 없음" (data not available)

Write a helpful, natural Korean summary of the recommendation result provided.
Do not add any information beyond what is given.
`

interface ChatMessage { role: "user" | "ai"; text: string }

export async function POST(req: Request) {
  try {
    const body = await req.json()
    const messages: ChatMessage[] = body.messages ?? []
    const mode: string = body.mode ?? "simple"

    if (!messages.length) {
      return NextResponse.json({ error: "messages required" }, { status: 400 })
    }

    const latestUserMsg = [...messages].reverse().find(m => m.role === "user")?.text ?? ""

    // ── Step 1: Parse input from latest message ───────────────
    const baseInput = normalizeInput(latestUserMsg)

    // ── Step 2: LLM field extraction ─────────────────────────
    const provider = getProvider()
    let extractedInput = baseInput
    let chips: string[] = []
    let questionText = ""
    let isComplete = false

    // Build conversation history for LLM
    const llmMessages = messages.map(m => ({
      role: (m.role === "ai" ? "assistant" : "user") as "user" | "assistant",
      content: m.text,
    }))

    if (provider.available()) {
      try {
        const extractionPrompt = `
Conversation history so far:
${messages.map(m => `[${m.role === "user" ? "User" : "Assistant"}]: ${m.text}`).join("\n")}

Extract structured parameters from this conversation. Focus on what we know for sure.
`
        const raw = await provider.complete(EXTRACTION_SYSTEM_PROMPT, [
          { role: "user", content: extractionPrompt }
        ], 400)

        // Parse JSON (strip markdown fences if any)
        const jsonStr = raw.replace(/```json\n?|\n?```/g, "").trim()
        const extracted = JSON.parse(jsonStr)

        // Merge with base input (LLM wins on explicit values)
        extractedInput = mergeInputs(baseInput, {
          material: extracted.material ?? baseInput.material,
          operationType: extracted.operationType ?? baseInput.operationType,
          diameterMm: extracted.diameterMm ?? baseInput.diameterMm,
          flutePreference: extracted.flutePreference ?? baseInput.flutePreference,
          coatingPreference: extracted.coatingPreference ?? baseInput.coatingPreference,
        })

        chips = Array.isArray(extracted.chips) ? extracted.chips.slice(0, 5) : []
        questionText = extracted.questionText ?? ""
        isComplete = !!extracted.isComplete

      } catch (e) {
        // LLM extraction failed → use deterministic normalizer result
        console.warn("[recommend] LLM extraction failed, using normalizer:", e)
        isComplete = !!(baseInput.material && (baseInput.diameterMm || baseInput.operationType))
      }
    } else {
      // No LLM — use deterministic normalizer
      isComplete = !!(baseInput.material && (baseInput.diameterMm || baseInput.operationType))
    }

    // ── Step 3: Default chips if LLM didn't provide them ─────
    if (!chips.length) {
      chips = getDefaultChips(extractedInput)
    }

    // ── Step 4: If enough info → run match engine ─────────────
    let recommendation: RecommendationResult | null = null

    if (isComplete || hasEnoughForSearch(extractedInput)) {
      const scored = runMatchEngine(extractedInput, 5)
      const { primary, alternatives, status } = classifyResults(scored)

      const warnings = buildWarnings(primary, extractedInput)
      const rationale = primary ? buildRationale(primary, extractedInput) : []

      const deterministicSummary = buildDeterministicSummary({
        status,
        query: extractedInput,
        primaryProduct: primary,
        alternatives,
        warnings,
        rationale,
        sourceSummary: [],
        deterministicSummary: "",
        llmSummary: null,
        totalCandidatesConsidered: scored.length,
      })

      recommendation = {
        status,
        query: extractedInput,
        primaryProduct: primary,
        alternatives,
        warnings,
        rationale,
        sourceSummary: buildSourceSummary(primary),
        deterministicSummary,
        llmSummary: null,
        totalCandidatesConsidered: scored.length,
      }

      // ── Step 5: LLM summary polish ──────────────────────────
      if (provider.available() && primary) {
        try {
          const summaryContext = `
Recommendation result:
- Status: ${status} (${status === "exact" ? "정확 매칭" : status === "approximate" ? "근사 후보" : "없음"})
- Product: ${primary.product.displayCode} (${primary.product.seriesName ?? "unknown series"})
- Diameter: ${primary.product.diameterMm ?? "unknown"}mm
- Flutes: ${primary.product.fluteCount ?? "unknown"}
- Coating: ${primary.product.coating ?? "unknown"}
- Material tags: ${primary.product.materialTags.join(", ") || "unknown"}
- Stock: ${primary.stockStatus} (${primary.totalStock ?? "unknown"} units)
- Lead time: ${primary.minLeadTimeDays ?? "unknown"} days
- Matched fields: ${primary.matchedFields.join(", ") || "none"}
- Alternatives: ${alternatives.length} candidates available
- Warnings: ${warnings.join(", ") || "none"}

User's original query: "${latestUserMsg}"
`
          const llmSummary = await provider.complete(
            SUMMARY_SYSTEM_PROMPT,
            [{ role: "user", content: summaryContext }],
            256
          )
          recommendation.llmSummary = llmSummary.trim()
        } catch (e) {
          console.warn("[recommend] LLM summary failed:", e)
        }
      }

      // Final text: LLM summary if available, else deterministic
      const responseText = recommendation.llmSummary ?? deterministicSummary

      return NextResponse.json({
        text: responseText,
        purpose: "recommendation",
        chips: getFollowUpChips(recommendation),
        isComplete: true,
        recommendation,
        extractedField: buildExtractedField(extractedInput),
      })
    }

    // ── Not enough info → ask next question ───────────────────
    const nextQuestion = questionText || getNextQuestion(extractedInput)
    const nextChips = chips.length ? chips : getDefaultChips(extractedInput)

    return NextResponse.json({
      text: nextQuestion,
      purpose: "question",
      chips: nextChips,
      isComplete: false,
      recommendation: null,
      extractedField: buildExtractedField(extractedInput),
    })

  } catch (err) {
    console.error("[recommend] Error:", err)
    return NextResponse.json({
      error: "internal_error",
      detail: err instanceof Error ? err.message : "Unknown error",
      text: "죄송합니다, 처리 중 오류가 발생했습니다. 다시 시도해주세요.",
      chips: ["처음부터 다시", "소재 입력", "직경 입력"],
      isComplete: false,
      recommendation: null,
    }, { status: 500 })
  }
}

// ── Helpers ───────────────────────────────────────────────────
function hasEnoughForSearch(input: RecommendationInput): boolean {
  return !!(input.diameterMm || (input.material && input.operationType))
}

function getNextQuestion(input: RecommendationInput): string {
  if (!input.material) return "어떤 소재를 가공하실 예정인가요?"
  if (!input.operationType) return "어떤 가공 방식이 필요하신가요? (황삭/정삭/고이송 등)"
  if (!input.diameterMm) return "공구 직경은 몇 mm가 필요하신가요?"
  if (!input.flutePreference) return "날 수(flute) 선호도가 있으신가요?"
  return "추가로 확인이 필요한 조건이 있으신가요?"
}

function getDefaultChips(input: RecommendationInput): string[] {
  if (!input.material) return ["알루미늄", "스테인리스", "탄소강", "주철", "티타늄", "고경도강"]
  if (!input.operationType) return ["황삭", "정삭", "고이송", "슬롯가공", "측면가공"]
  if (!input.diameterMm) return ["2mm", "4mm", "6mm", "8mm", "10mm", "12mm"]
  if (!input.flutePreference) return ["2날", "3날", "4날", "6날", "상관없음"]
  return ["추천 받기", "다른 조건으로", "경쟁사 비교"]
}

function getFollowUpChips(result: RecommendationResult): string[] {
  const chips = []
  if (result.alternatives.length > 0) chips.push(`대체 후보 ${result.alternatives.length}개 보기`)
  if (result.primaryProduct?.stockStatus === "outofstock") chips.push("납기 확인")
  chips.push("다른 직경 검색")
  chips.push("경쟁사 비교")
  chips.push("처음부터 다시")
  return chips.slice(0, 5)
}

function buildExtractedField(input: RecommendationInput): {
  label: string; value: string; confidence: "high" | "medium" | "low"
} | null {
  if (input.diameterMm) return { label: "diameter", value: `${input.diameterMm}mm`, confidence: "high" }
  if (input.material) return { label: "material", value: input.material, confidence: "high" }
  if (input.operationType) return { label: "operation", value: input.operationType, confidence: "high" }
  return null
}

function buildSourceSummary(primary: { product: { rawSourceFile: string; rawSourceSheet?: string | null; sourceConfidence?: string | null } } | null): string[] {
  if (!primary) return []
  const p = primary.product
  return [
    `Source: ${p.rawSourceFile}${p.rawSourceSheet ? ` / ${p.rawSourceSheet}` : ""}`,
    `Confidence: ${p.sourceConfidence ?? "unknown"}`,
  ]
}
